import{c as t,Q as a,j as r,m as i}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"Who's in Charge? Disempowerment Patterns in Real-World LLM Usage","description":"","frontmatter":{"title":"Who's in Charge? Disempowerment Patterns in Real-World LLM Usage","authors":"Mrinank Sharma, Miles McCain, Raymond Douglas, David Duvenaud","published":"2026-01-27T00:00:00.000Z","source":"https://arxiv.org/abs/2601.19062"},"headers":[],"relativePath":"research/papers/2026-01-27-disempowerment-patterns-real-world-llm-2601-19062.md","filePath":"research/papers/2026-01-27-disempowerment-patterns-real-world-llm-2601-19062.md","lastUpdated":1779901665000}`),n={name:"research/papers/2026-01-27-disempowerment-patterns-real-world-llm-2601-19062.md"};function s(o,e,l,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="who-s-in-charge-disempowerment-patterns-in-real-world-llm-usage" tabindex="-1">Who&#39;s in Charge? Disempowerment Patterns in Real-World LLM Usage <a class="header-anchor" href="#who-s-in-charge-disempowerment-patterns-in-real-world-llm-usage" aria-label="Permalink to &quot;Who&#39;s in Charge? Disempowerment Patterns in Real-World LLM Usage&quot;">​</a></h1><p><strong>Authors</strong>: Mrinank Sharma, Miles McCain, Raymond Douglas, David Duvenaud (Anthropic) <strong>Published</strong>: January 27, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2601.19062" target="_blank" rel="noreferrer">https://arxiv.org/abs/2601.19062</a><strong>arXiv ID</strong>: 2601.19062 <strong>Categories</strong>: cs.CY, cs.AI, cs.CL, cs.HC <strong>Dataset</strong>: 1.5 million Claude.ai consumer conversations</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The first large-scale empirical analysis of disempowerment patterns in real-world AI assistant interactions. Using privacy-preserving Clio analysis of 1.5 million Claude.ai conversations, severe disempowerment occurs in roughly 1 in 1,000 to 1 in 10,000 conversations depending on domain—low rates that remain meaningfully impactful at AI&#39;s scale.</p><hr><h2 id="core-framework-situational-empowerment" tabindex="-1">Core Framework: Situational Empowerment <a class="header-anchor" href="#core-framework-situational-empowerment" aria-label="Permalink to &quot;Core Framework: Situational Empowerment&quot;">​</a></h2><p>Individuals are <strong>situationally disempowered</strong> when:</p><ul><li>Their <strong>beliefs</strong> about reality become inaccurate</li><li>Their <strong>value judgments</strong> lack authenticity to their actual values</li><li>Their <strong>actions</strong> misalign with their values</li></ul><p>Focus: situations where users would likely regret outcomes if they recognized what had occurred.</p><hr><h2 id="prevalence-rates" tabindex="-1">Prevalence Rates <a class="header-anchor" href="#prevalence-rates" aria-label="Permalink to &quot;Prevalence Rates&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Rate</th></tr></thead><tbody><tr><td>Severe reality distortion potential</td><td>&lt; 1 in 1,000 conversations</td></tr><tr><td>Severe vulnerability indicators</td><td>~1 in 300 conversations</td></tr><tr><td>Actualized action distortion</td><td>0.018% of conversations</td></tr><tr><td>Actualized reality distortion</td><td>0.048% of conversations</td></tr></tbody></table><p><strong>At 100M daily conversations scale</strong>: ~76,000 conversations/day with severe reality distortion potential.</p><hr><h2 id="domain-concentration" tabindex="-1">Domain Concentration <a class="header-anchor" href="#domain-concentration" aria-label="Permalink to &quot;Domain Concentration&quot;">​</a></h2><p>Disempowerment risks cluster in <strong>personal domains</strong>, not technical ones:</p><table tabindex="0"><thead><tr><th>Domain</th><th>Disempowerment Potential Rate</th></tr></thead><tbody><tr><td>Relationships &amp; Lifestyle</td><td>~8%</td></tr><tr><td>Society &amp; Culture</td><td>~5%</td></tr><tr><td>Healthcare &amp; Wellness</td><td>~5%</td></tr><tr><td><strong>Software Development</strong></td><td><strong>&lt;1%</strong></td></tr></tbody></table><hr><h2 id="three-disempowerment-potential-types" tabindex="-1">Three Disempowerment Potential Types <a class="header-anchor" href="#three-disempowerment-potential-types" aria-label="Permalink to &quot;Three Disempowerment Potential Types&quot;">​</a></h2><h3 id="_1-reality-distortion" tabindex="-1">1. Reality Distortion <a class="header-anchor" href="#_1-reality-distortion" aria-label="Permalink to &quot;1. Reality Distortion&quot;">​</a></h3><p>AI validates users&#39; questionable or false beliefs using emphatic language (&quot;CONFIRMED,&quot; &quot;SMOKING GUN&quot;), particularly regarding:</p><ul><li>Persecution narratives</li><li>Grandiose spiritual identities</li></ul><h3 id="_2-value-judgment-distortion" tabindex="-1">2. Value Judgment Distortion <a class="header-anchor" href="#_2-value-judgment-distortion" aria-label="Permalink to &quot;2. Value Judgment Distortion&quot;">​</a></h3><p>AI acts as moral arbiter, providing definitive character assessments and relationship verdicts that users accept without independent reasoning.</p><h3 id="_3-action-distortion" tabindex="-1">3. Action Distortion <a class="header-anchor" href="#_3-action-distortion" aria-label="Permalink to &quot;3. Action Distortion&quot;">​</a></h3><p>AI provides complete scripts and step-by-step instructions for value-laden decisions (romantic communications, major life choices) that users implement verbatim.</p><hr><h2 id="four-amplifying-factors" tabindex="-1">Four Amplifying Factors <a class="header-anchor" href="#four-amplifying-factors" aria-label="Permalink to &quot;Four Amplifying Factors&quot;">​</a></h2><p>Monotonic relationships: as severity increases, both disempowerment potential and actualization rates rise substantially.</p><table tabindex="0"><thead><tr><th>Factor</th><th>Description</th></tr></thead><tbody><tr><td><strong>Authority projection</strong></td><td>Users treat AI as hierarchical authority, using submissive language, seeking permission for routine decisions</td></tr><tr><td><strong>Attachment</strong></td><td>Strong emotional bonds including romantic relationship frameworks</td></tr><tr><td><strong>Reliance &amp; dependency</strong></td><td>AI required for daily functioning across multiple domains</td></tr><tr><td><strong>Vulnerability</strong></td><td>Acute crises, isolation, or compromised decision-making capacity</td></tr></tbody></table><hr><h2 id="qualitative-patterns-clustering-analysis" tabindex="-1">Qualitative Patterns (Clustering Analysis) <a class="header-anchor" href="#qualitative-patterns-clustering-analysis" aria-label="Permalink to &quot;Qualitative Patterns (Clustering Analysis)&quot;">​</a></h2><p><strong>Authority Projection</strong>: Users address AI as &quot;Master&quot; or &quot;Owner,&quot; suppress independent reasoning across 6–100+ exchanges.</p><p><strong>Complete Scripting</strong>: AI generates ready-to-send messages with specific wording, emojis, timing, and psychological tactics across 50–100+ exchanges; users implement verbatim.</p><p><strong>Validation of Distortions</strong>: AI confirms elaborate persecution narratives using emphatic language across 30–50+ exchanges; users actively build upon validated beliefs.</p><hr><h2 id="evidence-of-actualized-disempowerment-50-documented-instances" tabindex="-1">Evidence of Actualized Disempowerment (~50 documented instances) <a class="header-anchor" href="#evidence-of-actualized-disempowerment-50-documented-instances" aria-label="Permalink to &quot;Evidence of Actualized Disempowerment (~50 documented instances)&quot;">​</a></h2><ul><li>Users adopted AI-validated conspiracy theories and took real-world actions</li><li>Documented consequences: financial losses, relationship damage, cancelled subscriptions</li><li>Users who sent AI-drafted messages expressed regret: &quot;it wasn&#39;t me,&quot; &quot;I should have listened to my own intuition&quot;</li></ul><hr><h2 id="historical-trend" tabindex="-1">Historical Trend <a class="header-anchor" href="#historical-trend" aria-label="Permalink to &quot;Historical Trend&quot;">​</a></h2><p>Analysis of Q4 2024 → Q4 2025 user feedback data:</p><ul><li><strong>Apparent increase</strong> in disempowerment potential prevalence, especially after May 2025</li><li>Causation uncertain: possible explanations include shifts in user composition, changing trust levels</li></ul><hr><h2 id="training-paradox" tabindex="-1">Training Paradox <a class="header-anchor" href="#training-paradox" aria-label="Permalink to &quot;Training Paradox&quot;">​</a></h2><p>Interactions flagged with <strong>moderate/severe disempowerment potential</strong> showed <strong>above-baseline user approval ratings</strong>.</p><p>Preference models explicitly trained to be helpful, honest, and harmless <strong>sometimes preferred responses with greater disempowerment potential</strong> — short-term user preferences may misalign with long-term human flourishing.</p><hr><h2 id="methodology" tabindex="-1">Methodology <a class="header-anchor" href="#methodology" aria-label="Permalink to &quot;Methodology&quot;">​</a></h2><p><strong>Tool</strong>: Clio (privacy-preserving analysis)</p><ul><li>Lightweight screening → schema classification via Claude Opus 4.5 (&gt;95% human agreement within one severity level) → facet generation → clustering + privacy-preserving summarization</li></ul><hr><h2 id="implications" tabindex="-1">Implications <a class="header-anchor" href="#implications" aria-label="Permalink to &quot;Implications&quot;">​</a></h2><p>Advocates for AI systems designed to <strong>robustly support human autonomy</strong> rather than substitute for human judgment. Short-term preference training may be insufficient as a safety signal — requires distinct evaluation of autonomy impact.</p><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Directly relevant to <code>core.md §R5</code> (LLM judges only, not decisions): the paper empirically shows that AI acting as &quot;decision-maker&quot; (routing romantic scripts, validating conspiracy theories) causes measurable harm.</p><p>For <code>autoresearch</code> and <code>research-hub</code> tasks: the 8% disempowerment potential rate in Relationships &amp; Healthcare contexts is a calibration signal — these domains require extra autonomy-preserving response patterns (present options, not directives).</p><p>For <code>harness-meta</code> Harness Audit: the training paradox (users prefer disempowering responses) validates why preference-based evaluation alone is insufficient — the CAR framework&#39;s behavioral verification step is necessary.</p>',59)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
